function haversineKm(a, b) {
  const R = 6371, toRad = (d) => (d * Math.PI) / 180;
  const dLat = toRad(b.lat - a.lat), dLng = toRad(b.lng - a.lng);
  const s = Math.sin(dLat / 2) ** 2 + Math.cos(toRad(a.lat)) * Math.cos(toRad(b.lat)) * Math.sin(dLng / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(s), Math.sqrt(1 - s));
}
const etaMinutes = (km) => Math.max(4, Math.round((km / 22) * 60)); // ~22km/h average town speed

// Deterministic small jitter so a technician's pin doesn't sit exactly on the locality dot
// (stable across re-renders — seeded from their id, not Math.random()).
function seededJitter(id, spread = 0.006) {
  let h = 0;
  for (let i = 0; i < id.length; i++) h = (h * 31 + id.charCodeAt(i)) >>> 0;
  const jx = ((h % 1000) / 1000 - 0.5) * spread;
  const jy = (((h >> 10) % 1000) / 1000 - 0.5) * spread;
  return { dLat: jy, dLng: jx };
}
function techLatLng(tech) {
  const home = LOCALITY_COORDS[tech.homeLocality] || LOCALITY_COORDS[LOCALITIES[0]];
  const j = seededJitter(tech.id);
  return { lat: home.lat + j.dLat, lng: home.lng + j.dLng };
}

