// Indicative only — for Puducherry, un-registered rent agreements (≤11 months) typically
// attract a small flat stamp duty; longer / registered leases scale with annual rent.
// Real amounts must be confirmed on the SHCIL e-stamping portal or with the Sub-Registrar.
function calcStampCharges(monthlyRent, deposit, durationMonths) {
  const annualRent = (monthlyRent || 0) * 12;
  if (durationMonths <= 11) {
    let stampDuty = 500;
    if (annualRent <= 50000) stampDuty = 100;
    else if (annualRent <= 200000) stampDuty = 200;
    return { stampDuty, registrationFee: 0, needsRegistration: false };
  }
  return { stampDuty: Math.max(200, Math.round(annualRent * 0.01)), registrationFee: 500, needsRegistration: true };
}

function next7Days() {
  const days = [];
  const names = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
  const today = new Date();
  for (let i = 0; i < 7; i++) {
    const d = new Date(today);
    d.setDate(today.getDate() + i);
    days.push({ key: d.toDateString(), label: i === 0 ? "Today" : names[d.getDay()], num: d.getDate() });
  }
  return days;
}

