/* =============================== SHARED CHROME =============================== */

function projectLatLng(lat, lng) {
  const x = ((lng - MAP_BOUNDS.minLng) / (MAP_BOUNDS.maxLng - MAP_BOUNDS.minLng)) * 100;
  const y = ((MAP_BOUNDS.maxLat - lat) / (MAP_BOUNDS.maxLat - MAP_BOUNDS.minLat)) * 100;
  return { x, y };
}

// A lightweight, dependency-free "map" — no external tile/JS-SDK is available inside this
// artifact sandbox, so pins are projected from real Puducherry lat/lng onto a stylised grid.
// It's not satellite imagery, but the geography and distances behind it are genuine.
function MiniMap({ pins, line, height = 170, className = "" }) {
  return (
    <div className={`relative rounded-xl overflow-hidden border ${className}`} style={{ borderColor: C.border, height, backgroundColor: "#E7EEF7" }}>
      <svg viewBox="0 0 100 100" preserveAspectRatio="none" className="absolute inset-0 w-full h-full">
        {[15, 30, 45, 60, 75, 90].map((v) => <line key={"h" + v} x1="0" y1={v} x2="100" y2={v} stroke="#D3DEEC" strokeWidth="0.4" />)}
        {[15, 30, 45, 60, 75, 90].map((v) => <line key={"v" + v} x1={v} y1="0" x2={v} y2="100" stroke="#D3DEEC" strokeWidth="0.4" />)}
        {line && (() => {
          const p1 = projectLatLng(line[0].lat, line[0].lng);
          const p2 = projectLatLng(line[1].lat, line[1].lng);
          return <line x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke={C.accent} strokeWidth="1" strokeDasharray="2.2,1.6" />;
        })()}
      </svg>
      {pins.map((p, i) => {
        const { x, y } = projectLatLng(p.lat, p.lng);
        return (
          <div key={i} className="absolute flex flex-col items-center" style={{ left: `${x}%`, top: `${y}%`, transform: "translate(-50%, -50%)" }}>
            {p.label && (
              <span className="text-[9px] font-semibold px-1.5 py-0.5 rounded-full mb-1 shadow-sm whitespace-nowrap" style={{ backgroundColor: "#fff", color: p.color || C.ink, border: `1px solid ${p.color || C.border}` }}>{p.label}</span>
            )}
            <div className="rounded-full border-2 border-white shadow" style={{ width: p.size || 11, height: p.size || 11, backgroundColor: p.color || C.primary }} />
          </div>
        );
      })}
      <span className="absolute bottom-1 right-1.5 text-[8px] px-1 rounded" style={{ backgroundColor: "#ffffffb0", color: C.sub }}>Puducherry, IN</span>
    </div>
  );
}

