function CustomerBookingCard({ booking: b, tech }) {
  const [showMap, setShowMap] = useState(false);
  const trackable = (b.status === "pending" || b.status === "accepted") && b.techCoord && b.customerCoord;
  return (
    <div className="bg-white rounded-xl p-3.5 shadow-sm border" style={{ borderColor: C.border }}>
      <div className="flex justify-between items-start">
        <p className="text-[12px]" style={{ color: C.sub }}>#{b.id} · {b.categoryName}</p>
        <StatusBadge status={b.status} />
      </div>
      {b.items.map((it, idx) => <p key={idx} className="text-[13px] font-semibold mt-1.5" style={{ color: C.ink }}>{it.qty}× {it.name}</p>)}
      <div className="flex items-center gap-3 mt-2 text-[11px]" style={{ color: C.sub }}>
        <span className="flex items-center gap-1"><Clock size={11} /> {b.date}, {b.slot}</span>
        <span className="flex items-center gap-1"><MapPin size={11} /> {b.locality}</span>
      </div>
      <div className="flex justify-between items-center mt-2.5 pt-2.5 border-t" style={{ borderColor: "#f0e6cc" }}>
        <span className="text-[11px]" style={{ color: C.sub }}>
          {tech ? (
            <span className="inline-flex items-center gap-1">Pro: {tech.name} <Star size={9} fill={C.amber} color={C.amber} />{tech.rating}</span>
          ) : "Awaiting assignment"}
        </span>
        <span className="text-[13px] font-bold" style={{ color: C.ink }}>{inr(b.total)}</span>
      </div>

      {trackable && (
        <div className="mt-2 rounded-lg overflow-hidden border" style={{ borderColor: C.border }}>
          <button onClick={() => setShowMap((s) => !s)} className="w-full flex items-center justify-between px-2.5 py-2" style={{ backgroundColor: C.primary + "0d" }}>
            <span className="text-[11px] font-semibold" style={{ color: C.primary }}>{tech?.name} is {b.distanceKm} km away · ETA ~{b.etaMins} min</span>
            <ChevronRight size={14} style={{ color: C.primary, transform: showMap ? "rotate(90deg)" : "none" }} />
          </button>
          {showMap && (
            <MiniMap
              height={150}
              line={[b.techCoord, b.customerCoord]}
              pins={[
                { lat: b.techCoord.lat, lng: b.techCoord.lng, color: C.primary, label: tech?.name, size: 12 },
                { lat: b.customerCoord.lat, lng: b.customerCoord.lng, color: C.accent, label: "You", size: 12 },
              ]}
            />
          )}
        </div>
      )}

      {(b.status === "pending" || b.status === "accepted") && (
        <div className="flex items-center justify-between mt-2 rounded-lg px-2.5 py-2" style={{ backgroundColor: C.primary + "0f" }}>
          <span className="text-[10.5px]" style={{ color: C.primary }}>Share this OTP only when the job is finished</span>
          <span className="text-[13px] font-mono font-bold" style={{ color: C.primary }}>{b.completionOtp}</span>
        </div>
      )}
    </div>
  );
}

