function TechnicianApp({ technicians, updateTechnician, bookings, updateBooking, onSwitch }) {
  const [techId, setTechId] = useState(null);
  const [tab, setTab] = useState("requests");
  const [otpInput, setOtpInput] = useState({});
  const [otpError, setOtpError] = useState({});
  const [jobsPerWeek, setJobsPerWeek] = useState(15);
  const tech = technicians.find((t) => t.id === techId);

  if (!tech) return <TechLogin technicians={technicians} onLogin={setTechId} onSwitch={onSwitch} />;

  const myPending = bookings.filter((b) => b.assignedTechId === tech.id && b.status === "pending").sort((a, b) => b.createdAt - a.createdAt);
  const myJobs = bookings.filter((b) => b.assignedTechId === tech.id && b.status === "accepted").sort((a, b) => b.createdAt - a.createdAt);
  const myCompleted = bookings.filter((b) => b.assignedTechId === tech.id && b.status === "completed").sort((a, b) => b.createdAt - a.createdAt);

  // Real, live demand near this technician — open jobs in their category, grouped by locality —
  // used to show the "demand map" and nudge them to go online in hot zones.
  const openInCategory = bookings.filter((b) => b.categoryId === tech.categoryId && (b.status === "pending" || b.status === "unassigned"));
  const demandByLocality = {};
  openInCategory.forEach((b) => { demandByLocality[b.locality] = (demandByLocality[b.locality] || 0) + 1; });
  const demandPins = Object.entries(demandByLocality).map(([loc, count]) => ({
    lat: LOCALITY_COORDS[loc].lat, lng: LOCALITY_COORDS[loc].lng, color: C.accent, label: `${loc} · ${count}`, size: 10 + Math.min(count, 5) * 3,
  }));
  const myCoord = techLatLng(tech);
  const monthlyEstimate = Math.round(jobsPerWeek * AVG_TICKET * (1 - COMMISSION_RATE) * 4.345);

  function accept(booking) {
    updateBooking(booking.id, { status: "accepted" });
  }
  function reject(booking) {
    const rejectedBy = [...(booking.rejectedBy || []), tech.id];
    const candidates = technicians.filter((t) => t.categoryId === booking.categoryId && t.online && !t.locked && !rejectedBy.includes(t.id));
    if (candidates.length > 0 && booking.customerCoord) {
      const nearest = candidates.map((t) => ({ t, coord: techLatLng(t), km: haversineKm(booking.customerCoord, techLatLng(t)) })).sort((a, b) => a.km - b.km)[0];
      updateBooking(booking.id, { status: "pending", assignedTechId: nearest.t.id, assignedTechName: nearest.t.name, techCoord: nearest.coord, distanceKm: Math.round(nearest.km * 10) / 10, etaMins: etaMinutes(nearest.km), rejectedBy });
    } else if (candidates.length > 0) {
      const next = candidates[Math.floor(Math.random() * candidates.length)];
      updateBooking(booking.id, { status: "pending", assignedTechId: next.id, assignedTechName: next.name, rejectedBy });
    } else {
      updateBooking(booking.id, { status: "unassigned", assignedTechId: null, assignedTechName: null, rejectedBy });
    }
  }

  // The core anti-fraud step: technician must enter the OTP only the customer has, proving
  // the job actually happened, before the app will let them close it and trigger commission collection.
  function completeWithOtp(booking) {
    const entered = (otpInput[booking.id] || "").trim();
    if (entered !== booking.completionOtp) {
      setOtpError((prev) => ({ ...prev, [booking.id]: "That OTP doesn't match. Ask the customer to confirm the code shown in their app." }));
      return;
    }
    setOtpError((prev) => ({ ...prev, [booking.id]: null }));

    const commission = Math.round(booking.total * COMMISSION_RATE);
    let walletBalance = tech.walletBalance;
    let commissionDue = tech.commissionDue;
    let commissionSettled;

    if (booking.paymentMethod === "prepaid") {
      // PondyService already collected the full amount online — commission never touches the
      // technician, it's simply withheld before payout. Zero collection risk on this path.
      commissionSettled = true;
    } else {
      // Cash job: technician is holding the customer's cash. Commission is auto-deducted from
      // their pre-funded wallet the instant the job closes — they never get a choice to skip it.
      if (walletBalance >= commission) {
        walletBalance -= commission;
        commissionSettled = true;
      } else {
        const shortfall = commission - walletBalance;
        walletBalance = 0;
        commissionDue += shortfall;
        commissionSettled = false;
      }
    }

    const locked = commissionDue > WALLET_LOCK_THRESHOLD;
    const netEarning = booking.total - commission;

    updateBooking(booking.id, { status: "completed", completedAt: Date.now(), commissionSettled, commissionAmount: commission });
    updateTechnician(tech.id, {
      completedJobs: tech.completedJobs + 1,
      earnings: tech.earnings + netEarning,
      walletBalance, commissionDue,
      locked,
      online: locked ? false : tech.online,
    });
    setOtpInput((prev) => ({ ...prev, [booking.id]: "" }));
  }

  function toggleOnline() {
    if (tech.locked && !tech.online) return; // can't go back online while dues are outstanding
    updateTechnician(tech.id, { online: !tech.online });
  }

  function topUpWallet(amount) {
    const payoff = Math.min(tech.commissionDue, amount);
    const newDue = tech.commissionDue - payoff;
    updateTechnician(tech.id, {
      commissionDue: newDue,
      walletBalance: tech.walletBalance + (amount - payoff),
      locked: newDue > WALLET_LOCK_THRESHOLD,
    });
  }

  return (
    <div className="min-h-screen" style={{ backgroundColor: C.bg }}>
      <AppHeader
        title={tech.name}
        subtitle={CATEGORY_BY_ID[tech.categoryId].name}
        onSwitch={onSwitch}
        right={
          <button onClick={() => setTechId(null)} title="Log out" className="p-1.5 rounded-lg" style={{ backgroundColor: "#ffffff1a" }}>
            <LogOut size={16} />
          </button>
        }
      />

      <div className="max-w-md mx-auto px-4 pt-4">
        {tech.locked && (
          <div className="rounded-xl border-2 p-3.5 mb-4 flex items-start gap-2" style={{ borderColor: C.red, backgroundColor: C.red + "0c" }}>
            <AlertTriangle size={18} style={{ color: C.red }} className="shrink-0 mt-0.5" />
            <div>
              <p className="text-[12.5px] font-bold" style={{ color: C.red }}>Account locked — {inr(tech.commissionDue)} commission overdue</p>
              <p className="text-[11px] mt-0.5" style={{ color: C.sub }}>You can't go online or accept new cash jobs until dues are cleared. Add funds to your wallet below to unlock instantly.</p>
            </div>
          </div>
        )}

        <div className="bg-white rounded-xl p-4 flex items-center justify-between shadow-sm border mb-4" style={{ borderColor: C.border }}>
          <div>
            <p className="text-[13px] font-semibold" style={{ color: C.ink }}>{tech.online ? "You're online" : "You're offline"}</p>
            <p className="text-[11px]" style={{ color: C.sub }}>{tech.online ? "Receiving new job requests" : tech.locked ? "Locked — clear dues to go online" : "Turn on to receive requests"}</p>
          </div>
          <button onClick={toggleOnline}>
            {tech.online ? <ToggleRight size={34} style={{ color: C.green }} /> : <ToggleLeft size={34} style={{ color: tech.locked ? C.red : C.sub }} />}
          </button>
        </div>

        <div className="bg-white rounded-xl p-4 shadow-sm border mb-4" style={{ borderColor: C.border }}>
          <div className="flex items-center gap-2 mb-3">
            <Wallet size={15} style={{ color: C.primary }} />
            <p className="text-[13px] font-bold" style={{ color: C.ink }}>Commission wallet</p>
          </div>
          <div className="grid grid-cols-2 gap-3 mb-3">
            <div>
              <p className="text-[10.5px]" style={{ color: C.sub }}>Wallet balance</p>
              <p className="text-[16px] font-bold" style={{ color: C.ink }}>{inr(tech.walletBalance)}</p>
            </div>
            <div>
              <p className="text-[10.5px]" style={{ color: C.sub }}>Commission due</p>
              <p className="text-[16px] font-bold" style={{ color: tech.commissionDue > 0 ? C.red : C.green }}>{inr(tech.commissionDue)}</p>
            </div>
          </div>
          <p className="text-[10px] mb-3" style={{ color: C.sub }}>PondyService keeps {Math.round(COMMISSION_RATE * 100)}% commission per job. For cash jobs it's auto-deducted from this wallet the moment you close the job; for prepaid jobs it's withheld automatically before payout.</p>
          <button onClick={() => topUpWallet(500)} className="w-full text-white rounded-lg py-2 text-[12px] font-semibold" style={{ backgroundColor: C.primary }}>+ Add ₹500 to wallet (demo top-up)</button>
        </div>

        {demandPins.length > 0 && (
          <div className="bg-white rounded-xl p-4 shadow-sm border mb-4" style={{ borderColor: C.border }}>
            <div className="flex items-center gap-2 mb-3">
              <Navigation size={15} style={{ color: C.accent }} />
              <p className="text-[13px] font-bold" style={{ color: C.ink }}>Demand near you — {CATEGORY_BY_ID[tech.categoryId].name}</p>
            </div>
            <MiniMap height={150} pins={[{ lat: myCoord.lat, lng: myCoord.lng, color: C.primary, label: "You", size: 13 }, ...demandPins]} />
            <p className="text-[10.5px] mt-2" style={{ color: C.sub }}>{openInCategory.length} open job{openInCategory.length !== 1 ? "s" : ""} waiting in your category right now. Stay online to get matched to the nearest one first.</p>
          </div>
        )}

        <div className="bg-white rounded-xl p-4 shadow-sm border mb-4" style={{ borderColor: C.border }}>
          <div className="flex items-center gap-2 mb-3">
            <TrendingUp size={15} style={{ color: C.green }} />
            <p className="text-[13px] font-bold" style={{ color: C.ink }}>Your earning potential</p>
          </div>
          <p className="text-[11px] mb-2" style={{ color: C.sub }}>If you complete <b style={{ color: C.ink }}>{jobsPerWeek} jobs/week</b>:</p>
          <input type="range" min="3" max="40" value={jobsPerWeek} onChange={(e) => setJobsPerWeek(Number(e.target.value))} className="w-full mb-2" />
          <p className="text-[22px] font-bold" style={{ color: C.green }}>{inr(monthlyEstimate)}<span className="text-[12px] font-normal" style={{ color: C.sub }}> / month estimated</span></p>
          <p className="text-[10px] mt-1" style={{ color: C.sub }}>Based on the average PondyService job value ({inr(AVG_TICKET)}) and your {Math.round((1 - COMMISSION_RATE) * 100)}% take-home share.</p>
        </div>

        <div className="grid grid-cols-3 gap-2.5 mb-5">
          <MiniStat icon={ClipboardList} label="Pending" value={myPending.length} color={C.amber} />
          <MiniStat icon={Briefcase} label="Active jobs" value={myJobs.length} color={C.primary} />
          <MiniStat icon={Wallet} label="Earnings" value={inr(tech.earnings)} color={C.green} small />
        </div>

        <div className="flex bg-white rounded-lg border p-1 mb-4" style={{ borderColor: C.border }}>
          {[["requests", `Requests (${myPending.length})`], ["jobs", `My jobs (${myJobs.length})`], ["history", "History"]].map(([k, label]) => (
            <button key={k} onClick={() => setTab(k)} className="flex-1 py-2 rounded-md text-[12px] font-semibold" style={tab === k ? { backgroundColor: C.primary, color: "#fff" } : { color: C.sub }}>{label}</button>
          ))}
        </div>
      </div>

      <div className="max-w-md mx-auto px-4 pb-10 flex flex-col gap-3">
        {tab === "requests" && (
          myPending.length === 0 ? <EmptyState icon={ClipboardList} text="No new requests right now." /> :
          myPending.map((b) => (
            <div key={b.id} className="bg-white rounded-xl p-3.5 shadow-sm border" style={{ borderColor: C.border }}>
              <div className="flex justify-between items-start mb-1.5">
                <p className="text-[12px]" style={{ color: C.sub }}>#{b.id} · New request</p>
                <span className="text-[13px] font-bold" style={{ color: C.ink }}>{inr(b.total)}</span>
              </div>
              {b.items.map((it, idx) => <p key={idx} className="text-[13px] font-semibold" style={{ color: C.ink }}>{it.qty}× {it.name}</p>)}
              <div className="flex items-center gap-3 mt-2 text-[11px]" style={{ color: C.sub }}>
                <span className="flex items-center gap-1"><Clock size={11} /> {b.date}, {b.slot}</span>
                <span className="flex items-center gap-1"><MapPin size={11} /> {b.locality}</span>
                {b.distanceKm != null && <span className="flex items-center gap-1" style={{ color: C.primary }}><Navigation size={11} /> {b.distanceKm} km · ~{b.etaMins} min</span>}
              </div>
              <div className="flex items-center justify-between mt-1">
                <p className="text-[11px]" style={{ color: C.sub }}>Customer: {b.customerName}</p>
                <span className="text-[9.5px] font-semibold px-1.5 py-0.5 rounded-full" style={{ backgroundColor: b.paymentMethod === "prepaid" ? C.primary + "18" : C.amber + "20", color: b.paymentMethod === "prepaid" ? C.primary : "#8a5a1d" }}>
                  {b.paymentMethod === "prepaid" ? "Prepaid online" : "Cash on service"}
                </span>
              </div>
              <div className="flex items-center justify-between mt-2 rounded-lg px-2.5 py-1.5" style={{ backgroundColor: C.green + "0f" }}>
                <span className="text-[10.5px]" style={{ color: C.green }}>You take home ({Math.round((1 - COMMISSION_RATE) * 100)}%)</span>
                <span className="text-[13px] font-bold" style={{ color: C.green }}>{inr(b.total * (1 - COMMISSION_RATE))}</span>
              </div>
              <div className="flex gap-2 mt-3">
                <button onClick={() => reject(b)} className="flex-1 flex items-center justify-center gap-1.5 border-2 rounded-lg py-2 text-[12px] font-semibold" style={{ borderColor: C.red, color: C.red }}><XCircle size={15} /> Reject</button>
                <button onClick={() => accept(b)} className="flex-1 flex items-center justify-center gap-1.5 text-white rounded-lg py-2 text-[12px] font-semibold" style={{ backgroundColor: C.green }}><CheckCircle2 size={15} /> Accept</button>
              </div>
            </div>
          ))
        )}

        {tab === "jobs" && (
          myJobs.length === 0 ? <EmptyState icon={Briefcase} text="No accepted jobs yet." /> :
          myJobs.map((b) => (
            <div key={b.id} className="bg-white rounded-xl p-3.5 shadow-sm border" style={{ borderColor: C.border }}>
              <div className="flex justify-between items-start mb-1.5">
                <p className="text-[12px]" style={{ color: C.sub }}>#{b.id}</p>
                <StatusBadge status={b.status} />
              </div>
              {b.items.map((it, idx) => <p key={idx} className="text-[13px] font-semibold" style={{ color: C.ink }}>{it.qty}× {it.name}</p>)}
              <div className="flex items-center gap-3 mt-2 text-[11px]" style={{ color: C.sub }}>
                <span className="flex items-center gap-1"><Clock size={11} /> {b.date}, {b.slot}</span>
                <span className="flex items-center gap-1"><MapPin size={11} /> {b.locality}, {b.address}</span>
              </div>
              <div className="flex items-center gap-1 mt-1 text-[11px]" style={{ color: C.sub }}><Phone size={11} /> {b.customerPhone}</div>
              <div className="mt-3 pt-3 border-t" style={{ borderColor: "#f0e6cc" }}>
                <p className="text-[11px] font-semibold mb-1.5" style={{ color: C.ink }}>Enter completion OTP from customer to close job</p>
                <div className="flex gap-2">
                  <input
                    value={otpInput[b.id] || ""}
                    onChange={(e) => setOtpInput((prev) => ({ ...prev, [b.id]: e.target.value.replace(/\D/g, "").slice(0, 4) }))}
                    placeholder="4-digit OTP"
                    className="flex-1 border rounded-lg px-3 py-2 text-[13px] font-mono tracking-widest"
                    style={{ borderColor: C.border }}
                  />
                  <button onClick={() => completeWithOtp(b)} className="text-white rounded-lg px-4 text-[12px] font-semibold" style={{ backgroundColor: C.primary }}>Complete</button>
                </div>
                {otpError[b.id] && <p className="text-[10.5px] mt-1.5" style={{ color: C.red }}>{otpError[b.id]}</p>}
              </div>
            </div>
          ))
        )}

        {tab === "history" && (
          myCompleted.length === 0 ? <EmptyState icon={CheckCircle2} text="Completed jobs will show up here." /> :
          myCompleted.map((b) => (
            <div key={b.id} className="bg-white rounded-xl p-3.5 shadow-sm border" style={{ borderColor: C.border }}>
              <div className="flex justify-between items-start mb-1.5">
                <p className="text-[12px]" style={{ color: C.sub }}>#{b.id}</p>
                <StatusBadge status={b.status} />
              </div>
              {b.items.map((it, idx) => <p key={idx} className="text-[13px] font-semibold" style={{ color: C.ink }}>{it.qty}× {it.name}</p>)}
              <div className="flex justify-between items-center mt-2 pt-2 border-t" style={{ borderColor: "#f0e6cc" }}>
                <span className="text-[11px]" style={{ color: C.sub }}>Commission {inr(b.commissionAmount || Math.round(b.total * COMMISSION_RATE))} · {b.commissionSettled === false ? "carried as dues" : "settled"}</span>
                <span className="text-[13px] font-bold" style={{ color: C.green }}>{inr(b.total - (b.commissionAmount || Math.round(b.total * COMMISSION_RATE)))}</span>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

